+                severity_color_code(self.severity),
+                " ".repeat(width.saturating_sub(2)),
+                severity_color_code(self.severity)
+            );
+
+            let alt_header = "Safe alternatives:";
+            let _ = writeln!(
+                output,
+                "\x1b[{}m\u{2502}\x1b[0m  \x1b[32m{}\x1b[0m{}  \x1b[{}m\u{2502}\x1b[0m",
+                severity_color_code(self.severity),
+                alt_header,
+                padding_for(alt_header, width.saturating_sub(4)),
+                severity_color_code(self.severity)
